INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('pukao-7ec62a85-moex-00102', 'pukao-7ec62a85', 'pukao-7ec62a85-moex-113-d1a761c9', 'sub-pukao-7ec62a85-02', NULL, 'single_choice', '甲之外籍配偶乙向我國駐外使領館申請入臺簽證，但經調查甲、乙婚姻真實性尚有可疑之處，乃拒絕 核發簽證。依憲法法庭裁判意旨，下列敘述何者正確？', '["因入臺簽證僅外國人須申請，甲非申請人故無提起行政救濟之權利", "甲與乙僅具有事實上或情感上之利害關係，故甲不得提起行政救濟", "基於維護婚姻與家庭關係，甲得提起課予義務訴訟尋求救濟", "因配偶經營共同生活之婚姻自由受侵害，甲得對該拒絕處分提起撤銷訴訟尋求救濟"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:42+00:00", "source_pdf_sha1": "6c3edb22667e", "answer_pdf_sha1": "1160bb07cdc1", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "420", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 46, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "法律廉政"}'::jsonb, NULL),
  ('pukao-7ec62a85-moex-00103', 'pukao-7ec62a85', 'pukao-7ec62a85-moex-113-d1a761c9', 'sub-pukao-7ec62a85-02', NULL, 'single_choice', '關於因公共設施設置或管理有欠缺，人民請求國家賠償之敘述，下列何者錯誤？', '["賠償義務機關，係指公共設施之管理機關", "管理機關，係指法令所定之管理機關或依法代為管理之機關", "設施雖非由國家設置，但事實上由其管理，並直接供公共或公務目的使用，仍屬國家賠償法所稱之 公共設施", "公共設施因設置或管理，致人民人身自由受損害者，國家不負損害賠償責任"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:42+00:00", "source_pdf_sha1": "6c3edb22667e", "answer_pdf_sha1": "1160bb07cdc1", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "420", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 47, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "法律廉政"}'::jsonb, NULL),
  ('pukao-7ec62a85-moex-00104', 'pukao-7ec62a85', 'pukao-7ec62a85-moex-113-d1a761c9', 'sub-pukao-7ec62a85-02', NULL, 'single_choice', '關於國家賠償之敘述，下列何者正確？', '["國家賠償請求權人，只能請求所受損害，不得請求其所失利益", "國家負損害賠償責任者，應以金錢為之。但以回復原狀為適當者，得依請求，回復損害發生前原狀", "國家賠償之請求權，自損害發生時起，因2年間不行使而消滅", "外國人為被害人時，不得請求國家賠償"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:42+00:00", "source_pdf_sha1": "6c3edb22667e", "answer_pdf_sha1": "1160bb07cdc1", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "420", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 48, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "法律廉政"}'::jsonb, NULL),
  ('pukao-7ec62a85-moex-00105', 'pukao-7ec62a85', 'pukao-7ec62a85-moex-113-d1a761c9', 'sub-pukao-7ec62a85-02', NULL, 'single_choice', '關於國家賠償法所規定之公務員國家賠償責任，下列敘述何者正確？', '["給付行政措施，不生公務員國家賠償責任", "受委託行使公權力者，於行使公權力時，亦適用公務員國家賠償責任", "為求人民權利保障之完整性，縱使公務員並無故意或過失，亦構成公務員國家賠償責任", "為使人民權利獲得全面性之保障，故公務員之不法行為與損害發生間，不以具有因果關係為必要"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:42+00:00", "source_pdf_sha1": "6c3edb22667e", "answer_pdf_sha1": "1160bb07cdc1", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "420", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 49, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "法律廉政"}'::jsonb, NULL),
  ('pukao-7ec62a85-moex-00106', 'pukao-7ec62a85', 'pukao-7ec62a85-moex-113-d1a761c9', 'sub-pukao-7ec62a85-02', NULL, 'single_choice', '有關行政裁量，下列敘述何者正確？', '["主管機關基於對外國人原國籍之厭惡，否准其歸化申請，乃裁量之濫用", "行政機關於訂定裁罰基準後，即不得於個案裁處時再為裁量", "法規授予行政機關裁量時，法院即不得審查該裁量決定", "法規授予行政機關裁量時，上級機關亦不得訂定統一之裁量基準"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:42+00:00", "source_pdf_sha1": "6c3edb22667e", "answer_pdf_sha1": "1160bb07cdc1", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "420", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 50, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "法律廉政"}'::jsonb, NULL),
  ('pukao-7ec62a85-moex-00107', 'pukao-7ec62a85', 'pukao-7ec62a85-moex-112-9a3b44c4', 'sub-pukao-7ec62a85-03', NULL, 'essay', '我國刑事訴訟法之傳聞例外有幾種類型？試分別舉例說明之。（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:42+00:00", "source_pdf_sha1": "6c63a30d632a", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "415", "s": "1214", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "刑事訴訟法概要", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "法律廉政"}'::jsonb, NULL),
  ('pukao-7ec62a85-moex-00108', 'pukao-7ec62a85', 'pukao-7ec62a85-moex-112-9a3b44c4', 'sub-pukao-7ec62a85-03', NULL, 'essay', '張三與李四二人共犯殺人罪，張三於落網後否認犯罪，惟因犯嫌重大，
