  ('pukao-7ec62a85-moex-00111', 'pukao-7ec62a85', 'pukao-7ec62a85-moex-112-e2754278', 'sub-pukao-7ec62a85-04', NULL, 'essay', '某甲駕車在市區林蔭大道上行駛，為了響應環保節能減碳，甲不開冷氣，
而是將車窗打開吹風。行駛中，不知何處來的一隻喜鵲從窗外飛進車內，
並亂啄攻擊甲。甲猝遭喜鵲攻擊，慌亂之中無法控制車行方向，車子因而
衝上人行道撞上路人乙，導致乙身體多處受有挫傷及擦傷。嗣乙對甲提出
告訴，試問甲有何刑責？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:42+00:00", "source_pdf_sha1": "8f4b9256a909", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "415", "s": "1212", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "刑法概要", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "法律廉政"}'::jsonb, NULL)
